import * as React from 'react';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';
import { Typography } from '@mui/material';

import CssBaseline from '@mui/material/CssBaseline';



function Hero () {
	return (
		<>
			<CssBaseline />
			<Box display='flex' height={'100vh'} sx={{ alignItems: 'center', backgroundColor: 'grey' }}>
				<Box flex='1' width={100}>
					<Typography variant='h1' sx={{ backgroundColor: 'blue', textAlign: 'center', fontSize: 40 }}>
						Title Here
					</Typography>
					<Typography variant='h2' sx={{ backgroundColor: 'blue', textAlign: 'center', fontSize: 30 }}>
						Subtitle here
					</Typography>
				</Box>
			</Box>
		</>
	)
}

export default Hero;
